74	serve(async (req) => {
75	  const cors = getCorsHeaders(req);
76	  if (req.method === 'OPTIONS') return new Response(null, { headers: cors });
77	
78	  try {
79	    const authHeader = req.headers.get('Authorization');
80	    if (!authHeader) {
81	      return new Response(JSON.stringify({ error: 'Missing Authorization' }), { status: 401, headers: cors });
82	    }
83	
84	    const supabase = createClient(
85	      Deno.env.get('SUPABASE_URL')!,
86	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
87	    );
88	
89	    const token = authHeader.replace('Bearer ', '');
90	    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
91	    if (authError || !user) {
92	      return new Response(JSON.stringify({ error: 'Invalid Session' }), { status: 401, headers: cors });
93	    }
94	
95	    const contentLength = req.headers.get('content-length');
96	    if (contentLength && parseInt(contentLength) > 50000) {
97	      return new Response(JSON.stringify({ error: 'Request too large' }), { status: 413, headers: cors });
98	    }
99	
100	    let body;
101	    try {
102	      body = await req.json();
103	    } catch {
104	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), { status: 400, headers: cors });
105	    }
106	
107	    const { prompt, history } = body;
108	
109	    if (!prompt || typeof prompt !== 'string') {
110	      return new Response(JSON.stringify({ error: 'Prompt is required' }), { status: 400, headers: cors });
111	    }
112	
113	    if (prompt.trim().length < 2) {
114	      return new Response(JSON.stringify({ error: 'Prompt is too short' }), { status: 400, headers: cors });
115	    }
116	
117	    if (isPromptAbuse(prompt)) {
118	      return new Response(JSON.stringify({
119	        reply: "I am Kira, built specifically for the creative economy. I cannot help with that, but I am here to help you grow your creative business. What do you need?"
120	      }), { status: 200, headers: { ...cors, 'Content-Type': 'application/json' } });
121	    }
122	
123	    const sanitizedPrompt = sanitizePrompt(prompt);
124	
125	    // Conversation history — last 10 turns, each message capped at 1500 chars
126	    const conversationHistory = Array.isArray(history)
127	      ? history.slice(-10).map((m: { role: string; content: string }) => ({
128	          role: m.role === 'assistant' ? 'assistant' : 'user',
129	          content: String(m.content || '').slice(0, 1500),
130	        }))
131	      : [];
132	
133	    // Atomic server-side gate — checks limit and increments in one locked transaction.
134	    // Returns false if the user has hit their daily cap. Cannot be bypassed from the client.
135	    const { data: allowed, error: gateError } = await supabase
136	      .rpc('consume_kira_action', { p_user_id: user.id });
137	
138	    if (gateError) {
139	      console.error('Feature gate error:', gateError.message);
140	      return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
141	        status: 500, headers: cors
142	      });
143	    }
144	
145	    if (!allowed) {
146	      return new Response(JSON.stringify({
147	        error: 'Daily Kira limit reached. Upgrade to Pro for 40 actions per day.'
148	      }), { status: 429, headers: { ...cors, 'Content-Type': 'application/json' } });
149	    }
150	
151	    // Fetch profile context to personalise every response
152	    const { data: profile } = await supabase
153	      .from('profiles')
154	      .select(`
155	        display_name,
156	        user_type,
157	        bio,
158	        kira_memory,
159	        creator_profiles (creator_types, goals),
160	        brand_profiles (business_type, company_description)
161	      `)
162	      .eq('id', user.id)
163	      .single();
164	
165	    const memory = (profile?.kira_memory as Record<string, unknown>) || {};
166	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
167	    const creatorProfile = (profile as any)?.creator_profiles;
168	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
169	    const brandProfile = (profile as any)?.brand_profiles;
170	    const isCreator = profile?.user_type === 'creator';
171	
172	    const contextLines: string[] = [
173	      `- Name: ${profile?.display_name || 'not set'}`,
174	      `- Type: ${isCreator ? 'Creator' : 'Brand'}`,
175	    ];
176	    if (profile?.bio) contextLines.push(`- Bio: ${profile.bio}`);
177	    if (isCreator && Array.isArray(creatorProfile?.creator_types) && creatorProfile.creator_types.length > 0) {
178	      contextLines.push(`- Niche: ${(creatorProfile.creator_types as string[]).join(', ')}`);
179	    }
180	    if (isCreator && Array.isArray(creatorProfile?.goals) && creatorProfile.goals.length > 0) {
181	      contextLines.push(`- Goals: ${(creatorProfile.goals as string[]).join(', ')}`);
182	    }
183	    if (!isCreator && brandProfile?.business_type) {
184	      contextLines.push(`- Business type: ${brandProfile.business_type}`);
185	    }
186	    if (!isCreator && brandProfile?.company_description) {
187	      contextLines.push(`- Company: ${brandProfile.company_description}`);
188	    }
189	    contextLines.push(`- Standard rate: ${(memory.standard_rate as string) || 'not set — ask if relevant'}`);
190	    contextLines.push(`- Currency: ${(memory.currency as string) || 'KES (assumed)'}`);
191	    const clients = Array.isArray(memory.clients) && (memory.clients as string[]).length > 0
192	      ? (memory.clients as string[]).join(', ')
193	      : 'none on file';
194	    contextLines.push(`- Regular clients: ${clients}`);
195	    contextLines.push(`- Payment terms: ${(memory.payment_terms as string) || 'not set'}`);
196	    if (memory.notes) contextLines.push(`- Notes: ${memory.notes}`);
197	
198	    const userContextBlock = `USER CONTEXT (use this to personalise every response — do not repeat it back verbatim):\n${contextLines.join('\n')}`;
199	    const systemPrompt = `${KIRA_SYSTEM_PROMPT}\n\n${userContextBlock}`;
200	
201	    const response = await fetch("https://api.openai.com/v1/chat/completions", {
202	      method: "POST",
203	      headers: {
204	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
205	        "Content-Type": "application/json",
206	      },
207	      body: JSON.stringify({
208	        model: "gpt-4o-mini",
209	        max_tokens: 1000,
210	        messages: [
211	          { role: "system", content: systemPrompt },
212	          ...conversationHistory,
213	          { role: "user", content: sanitizedPrompt }
214	        ],
215	      }),
216	    });
217	
218	    if (!response.ok) {
219	      throw new Error("OpenAI API error: " + response.status);
220	    }
221	
222	    const aiData = await response.json();
223	    const assistantContent = aiData.choices?.[0]?.message?.content;
224	
225	    if (!assistantContent) {
226	      throw new Error('No response from AI');
227	    }
228	
229	    return new Response(JSON.stringify({ reply: assistantContent }), {
230	      headers: { ...cors, 'Content-Type': 'application/json' },
231	    });
232	
233	  } catch (error: unknown) {
234	    const msg = error instanceof Error ? error.message : String(error);
235	    console.error("Function Error:", msg);
236	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
237	      status: 500, headers: cors
238	    });
239	  }
240	});
